import logging
import json
import re
from typing import List, Optional, Dict, Any
from pydantic import BaseModel, Field
from src.config import settings

logger = logging.getLogger(__name__)

class PlannedTask(BaseModel):
    """A single sub-task generated by the QueryPlanner."""
    task_id: int
    description: str
    search_query: str
    requires_graph: bool = Field(default=False, description="Whether this task needs relationship search")
    dependency_ids: List[int] = Field(default_factory=list, description="IDs of tasks that must be completed first")

class ExecutionPlan(BaseModel):
    """The full execution plan for a legal query."""
    tasks: List[PlannedTask]
    strategy: str = Field(description="Search strategy: simple, multi_step, or graph_enriched")

