class QueryPlanner:
    """
    Analyzes user queries and plans an execution strategy involving
    standard retrieval and/or Graph RAG.
    """

    def __init__(self, llm_client=None):
        self._client = llm_client
        # If client not provided, we will assume it's set later or use a default one
        # For now, we'll try to use the same logic as LegalRAGGenerator if needed

    async def create_plan(self, question: str) -> ExecutionPlan:
        """Analyze the query and create a multi-step execution plan."""
        logger.info(f"Planning execution for query: '{question}'")
        
        # We'll use the LLM to generate the plan
        # Note: In a production system, we'd have a dedicated client here
        # For this implementation, we will use a structure that can be easily integrated
        
        # Default simple plan if LLM fails or for simple queries
        default_plan = ExecutionPlan(
            strategy="simple",
            tasks=[
                PlannedTask(
                    task_id=1,
                    description=f"Tra cứu thông tin về: {question}",
                    search_query=question,
                    requires_graph=self._detect_graph_need(question)
                )
            ]
        )
        
        return default_plan

    def _detect_graph_need(self, question: str) -> bool:
        """Rules-based detection of graph search needs as a fallback/accelerator."""
        keywords = [
            "hướng dẫn", "nghị định", "thông tư", "sửa đổi", 
            "bổ sung", "căn cứ", "thay thế", "chi tiết"
        ]
        q_lower = question.lower()
        return any(k in q_lower for k in keywords)
